from flask import Flask, request, jsonify, session
from werkzeug.security import generate_password_hash, check_password_hash
import re

app = Flask(__name__)
app.secret_key = 'your_secret_key'  # Change this to a strong secret key

# Mock database for demonstration purposes
users_db = {
    'user@example.com': {
        'password': generate_password_hash('old_password'),
        'two_factor_enabled': False
    }
}

def is_valid_email(email):
    return re.match(r"[^@]+@[^@]+\.[^@]+", email)

@app.route('/update_profile', methods=['POST'])
def update_profile():
    if 'user' not in session:
        return jsonify({'error': 'Unauthorized'}), 401

    user_email = session['user']
    user_data = users_db.get(user_email)

    if not user_data:
        return jsonify({'error': 'User not found'}), 404

    data = request.json
    new_email = data.get('email')
    new_password = data.get('password')
    two_factor_enabled = data.get('two_factor_enabled')

    if new_email and not is_valid_email(new_email):
        return jsonify({'error': 'Invalid email format'}), 400

    if new_email and new_email != user_email:
        users_db[new_email] = users_db.pop(user_email)
        user_email = new_email
        session['user'] = new_email

    if new_password:
        user_data['password'] = generate_password_hash(new_password)

    if two_factor_enabled is not None:
        user_data['two_factor_enabled'] = two_factor_enabled

    return jsonify({'message': 'Profile updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)